const { createReadStream } = require('fs')
// loads 'createReadStream' from the built-in 'fs' module
// createReadStream reads a file piece by piece (in chunks) instead of all at once
// This is memory-efficient — crucial for large files (videos, logs, datasets)

const stream = createReadStream('./content/big.txt')
// creates a readable stream pointing to 'big.txt' (generated by 17_creating_bigFiles.js)
// the file is NOT read yet — the stream is just set up and ready
// default chunk size is 64KB — Node reads 64KB at a time, fires 'data', reads next 64KB, etc.

stream.on('data', (result) => {
    // registers a listener for the 'data' event
    // fires every time a new chunk (piece) of the file is available
    // 'result' is a Buffer object containing the chunk's raw bytes
    // for a 10,000-line file, this event fires MULTIPLE times until all chunks are delivered
    console.log(result);
    // prints each Buffer chunk to the terminal
    // you'd normally convert it: result.toString() to get readable text
})

stream.on('error', (err) => {
    // registers a listener for the 'error' event
    // fires if something goes wrong during streaming
    // common causes: file doesn't exist, permission denied, disk error
    console.log(err);
    // prints the error object — tells you what went wrong and where
    // NOTE: better practice is console.error(err) for error output
})

/**
 Why use createReadStream()?

❌ readFile() — loads everything into RAM at once:
const { readFile } = require('fs')

readFile('./content/big.txt', 'utf8', (err, data) => {
    console.log(data)
})
Loads the entire file into memory before giving it to you.
Not ideal for very large files — can crash with out-of-memory errors.

✅ createReadStream() — reads piece by piece:
const stream = createReadStream('./content/big.txt')
Reads the file piece by piece (chunks = 64KB at a time by default).
Uses MUCH less memory — only one chunk lives in memory at a time.
Faster for large files — starts processing before the whole file is read.
Commonly used for: videos, logs, large datasets, and file downloads.

Events Used:
"data"  → fired whenever a new chunk is available (can fire many times per file)
"error" → fired when something goes wrong (file missing, no permission, etc.)

Example error:
Error: ENOENT: no such file or directory, open './content/big.txt'
→ Fix: run 17_creating_bigFiles.js first to generate the file
 */